const { ApolloServer, gql, PubSub } = require('apollo-server-express');
const express = require('express');
const { createServer } = require('http');
const { execute, subscribe } = require('graphql');
const { SubscriptionServer } = require('subscriptions-transport-ws');
const cors = require('cors');

const pubsub = new PubSub();
const ROOM_ADDED = 'ROOM_ADDED';
const MESSAGE_ADDED = 'MESSAGE_ADDED';

const typeDefs = gql`
  type Message {
    id: ID!
    content: String!
    author: String!
    timestamp: String!
    roomId: String!
  }

  type Room {
    id: ID!
    name: String!
    createdAt: String!
  }

  type Query {
    rooms: [Room!]!
    messages(roomId: String!): [Message!]!
  }

  type Mutation {
    addRoom(name: String!): Room!
    addMessage(roomId: String!, content: String!, author: String!): Message!
  }

  type Subscription {
    messageAdded(roomId: String!): Message!
    roomAdded: Room!
  }
`;

const rooms = new Map();
const messages = new Map();

const resolvers = {
  Query: {
    rooms: () => {
      return Array.from(rooms.values());
    },
    messages: (_, { roomId }) => {
      return messages.get(roomId) || [];
    },
  },
  Mutation: {
    addRoom: (_, { name }) => {
      const room = {
        id: Date.now().toString(),
        name,
        createdAt: new Date().toISOString(),
      };
      rooms.set(room.id, room);
      pubsub.publish(ROOM_ADDED, { roomAdded: room });
      return room;
    },
    addMessage: (_, { roomId, content, author }) => {
      if (!rooms.has(roomId)) {
        throw new Error('Room not found');
      }
      
      const message = {
        id: Date.now().toString(),
        content,
        author,
        timestamp: new Date().toISOString(),
        roomId,
      };
      
      if (!messages.has(roomId)) {
        messages.set(roomId, []);
      }
      
      messages.get(roomId).push(message);
      pubsub.publish(MESSAGE_ADDED, { messageAdded: message });
      return message;
    },
  },
  Subscription: {
    messageAdded: {
      subscribe: (_, { roomId }) => {
        return pubsub.asyncIterator([MESSAGE_ADDED]);
      },
      resolve: (payload) => {
        return payload.messageAdded;
      },
    },
    roomAdded: {
      subscribe: () => pubsub.asyncIterator([ROOM_ADDED]),
    },
  },
};

const app = express();
app.use(cors());

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req, connection }) => {
    if (connection) {
      return connection.context;
    }
    return { req };
  },
});

const httpServer = createServer(app);

server.start().then(() => {
  server.applyMiddleware({ app, path: '/graphql' });
  
  const subscriptionServer = SubscriptionServer.create(
    {
      schema: server.schema,
      execute,
      subscribe,
    },
    {
      server: httpServer,
      path: server.graphqlPath,
    }
  );
  
  httpServer.listen(4000, () => {
    console.log('Server ready at http://localhost:4000/graphql');
  });
});